//! tts-probe — speech-OUT admission probe for forkjoin-ai/qwen3-tts-12hz-0.6b.
//!
//! The speech-OUT counterpart to whisper-probe (speech-IN). Mirrors vl-probe's
//! "load knot → run modality module → looser structural gate" shape, but for
//! generative audio the bar is a STRUCTURAL / coherence gate (Taylor's looser
//! gate for generative output): the codec decoder must produce VALID,
//! NON-DEGENERATE audio, not bit-exact speech.
//!
//! Pipeline
//! --------
//!   1. Load the dense `.knot` (carries the talker text backbone + the carried
//!      codec decoder `tts_codec_*`).
//!   2. Obtain a `[n_frames, 16]` codec-token matrix to decode. Two sources:
//!        --codes <bin>   a fixture: [u32 n_frames][u32 nq] then u32 codes
//!                        (row-major n_frames×nq). Always-available structural
//!                        proof of the codec decoder (tokens → waveform).
//!        --talker        (future) run the talker LM on --text-tokens to emit
//!                        codes end-to-end. Wired behind a flag; the codec gate
//!                        is identical either way.
//!   3. Decode via `Qwen3TtsCodecDecoder` → mono f32 PCM @ 24 kHz.
//!   4. STRUCTURAL GATE (all must hold):
//!        - finite:        no NaN / Inf samples
//!        - non-empty:     len >= 1 frame of output (n_frames * 1920)
//!        - length:        |len - n_frames*1920| within a small causal slack
//!        - variance:      std(samples) > MIN_STD  (not silence / a constant)
//!        - not clipped-flat: peak in (0, 1.5]  (real signal, not a rail)
//!        - dynamic range: > MIN_DR dB above the noise floor (tracks structure)
//!   5. Writes /tmp/tts-probe/out.wav for inspection (best-effort).
//!
//! Exit 0 on PASS, 1 on FAIL, 2 on usage error.
//!
//! Usage
//! -----
//! ```
//! tts-probe --knot /workspace/qwen3-tts-12hz-0.6b.knot \
//!           --codes /tmp/fox_codes.bin
//! ```
//! Generate a "the quick brown fox" fixture with the talker offline (or sample
//! valid codes) and pass it via --codes; the gate proves the carried decoder
//! turns codec tokens into coherent waveform on the mesh.

use std::path::PathBuf;
use std::sync::Arc;
use std::time::Instant;

use distributed_inference::loader::KnotWeights;
use distributed_inference::model_qwen3_tts_codec::{Qwen3TtsCodecConfig, Qwen3TtsCodecDecoder};
use distributed_inference::model_qwen3_tts_talker::{Qwen3TtsTalker, Qwen3TtsTalkerConfig};

fn die(msg: impl AsRef<str>) -> ! {
    eprintln!("tts-probe: {}", msg.as_ref());
    std::process::exit(2);
}

struct Args {
    knot: String,
    codes: Option<PathBuf>,
    text_ids: Option<Vec<u32>>,
    out_wav: String,
}

fn parse_args() -> Args {
    let mut knot: Option<String> = None;
    let mut codes: Option<PathBuf> = None;
    let mut text_ids: Option<Vec<u32>> = None;
    let mut out_wav = "/tmp/tts-probe/out.wav".to_string();
    let raw: Vec<String> = std::env::args().skip(1).collect();
    let mut i = 0;
    while i < raw.len() {
        match raw[i].as_str() {
            "--knot" => {
                i += 1;
                knot = Some(
                    raw.get(i)
                        .unwrap_or_else(|| die("--knot needs a path"))
                        .clone(),
                );
            }
            "--codes" => {
                i += 1;
                codes = Some(PathBuf::from(
                    raw.get(i).unwrap_or_else(|| die("--codes needs a path")),
                ));
            }
            "--out" => {
                i += 1;
                out_wav = raw
                    .get(i)
                    .unwrap_or_else(|| die("--out needs a path"))
                    .clone();
            }
            "--text-ids" => {
                i += 1;
                let s = raw.get(i).unwrap_or_else(|| die("--text-ids needs a comma-separated u32 list"));
                let ids: Vec<u32> = s.split(',').filter(|t| !t.trim().is_empty())
                    .map(|t| t.trim().parse::<u32>().unwrap_or_else(|_| die(format!("bad text id: {t}"))))
                    .collect();
                if ids.is_empty() { die("--text-ids parsed to empty list"); }
                text_ids = Some(ids);
            }
            "--text-ids-file" => {
                i += 1;
                let p = raw.get(i).unwrap_or_else(|| die("--text-ids-file needs a path"));
                let s = std::fs::read_to_string(p).unwrap_or_else(|e| die(format!("read --text-ids-file {p}: {e}")));
                let ids: Vec<u32> = s.split([',', '\n', ' ', '\t'])
                    .filter(|t| !t.trim().is_empty())
                    .map(|t| t.trim().parse::<u32>().unwrap_or_else(|_| die(format!("bad text id: {t}"))))
                    .collect();
                if ids.is_empty() { die("--text-ids-file parsed to empty list"); }
                text_ids = Some(ids);
            }
            "-h" | "--help" => {
                eprintln!("usage: tts-probe --knot <path> (--codes <bin> | --text-ids <csv> | --text-ids-file <path>) [--out <wav>]");
                std::process::exit(0);
            }
            other => die(format!("unknown arg: {other}")),
        }
        i += 1;
    }
    if codes.is_none() && text_ids.is_none() {
        die("need --codes (codec fixture) OR --text-ids/--text-ids-file (talker)");
    }
    Args {
        knot: knot.unwrap_or_else(|| die("--knot required")),
        codes,
        text_ids,
        out_wav,
    }
}

/// Read a codec-token fixture: [u32 n_frames][u32 nq] then n_frames*nq u32 codes.
fn read_codes(path: &PathBuf) -> (usize, usize, Vec<u32>) {
    let bytes = std::fs::read(path).unwrap_or_else(|e| die(format!("read codes {path:?}: {e}")));
    if bytes.len() < 8 {
        die("codes file too short (need 8-byte header)");
    }
    let n_frames = u32::from_le_bytes(bytes[0..4].try_into().unwrap()) as usize;
    let nq = u32::from_le_bytes(bytes[4..8].try_into().unwrap()) as usize;
    let expected = n_frames * nq;
    let payload = &bytes[8..];
    if payload.len() != expected * 4 {
        die(format!(
            "codes payload {} u32 != n_frames*nq {n_frames}*{nq}={expected}",
            payload.len() / 4
        ));
    }
    let codes: Vec<u32> = payload
        .chunks_exact(4)
        .map(|c| u32::from_le_bytes([c[0], c[1], c[2], c[3]]))
        .collect();
    (n_frames, nq, codes)
}

// ── structural-gate thresholds ────────────────────────────────────────────
const MIN_STD: f32 = 1e-3; // below this = silence / a constant rail
const MAX_PEAK: f32 = 1.5; // peak must stay in (0, MAX_PEAK]; >1.5 = blown up
const MIN_DR_DB: f32 = 6.0; // dynamic range (peak vs noise floor), dB

fn write_wav(path: &str, samples: &[f32], sample_rate: usize) -> std::io::Result<()> {
    use std::io::Write;
    if let Some(parent) = std::path::Path::new(path).parent() {
        std::fs::create_dir_all(parent)?;
    }
    let mut f = std::fs::File::create(path)?;
    let n = samples.len();
    let byte_rate = sample_rate * 2;
    let data_bytes = (n * 2) as u32;
    f.write_all(b"RIFF")?;
    f.write_all(&(36 + data_bytes).to_le_bytes())?;
    f.write_all(b"WAVE")?;
    f.write_all(b"fmt ")?;
    f.write_all(&16u32.to_le_bytes())?;
    f.write_all(&1u16.to_le_bytes())?; // PCM
    f.write_all(&1u16.to_le_bytes())?; // mono
    f.write_all(&(sample_rate as u32).to_le_bytes())?;
    f.write_all(&(byte_rate as u32).to_le_bytes())?;
    f.write_all(&2u16.to_le_bytes())?; // block align
    f.write_all(&16u16.to_le_bytes())?; // bits/sample
    f.write_all(b"data")?;
    f.write_all(&data_bytes.to_le_bytes())?;
    for &s in samples {
        let v = (s.clamp(-1.0, 1.0) * 32767.0) as i16;
        f.write_all(&v.to_le_bytes())?;
    }
    Ok(())
}

fn main() {
    let args = parse_args();
    let t_all = Instant::now();
    eprintln!(
        "tts-probe: knot={} mode={}",
        args.knot,
        if args.text_ids.is_some() { "talker" } else { "codec-fixture" }
    );

    // 1. Load the dense knot.
    let t_load = Instant::now();
    let knot = KnotWeights::load(&args.knot).unwrap_or_else(|e| die(format!("knot load: {e}")));
    eprintln!("  loaded knot in {:.2}s", t_load.elapsed().as_secs_f32());
    let backend = Arc::clone(&knot.backend);

    // Fail fast if the codec decoder was not carried into the knot.
    if !Qwen3TtsCodecDecoder::is_present(&backend) {
        die(
            "knot has no tts_codec_* tensors — codec decoder was NOT encoded. \
             Re-encode with the qwen3_tts branch of encode-knot.py.",
        );
    }

    let cfg = Qwen3TtsCodecConfig::default();

    // 2. Obtain a [n_frames, nq] codec-token matrix — fixture or talker.
    let (n_frames, nq, codes) = if let Some(text_ids) = &args.text_ids {
        if !Qwen3TtsTalker::is_present(&backend) {
            die(
                "knot has no tts_talker_* tensors — talker text→codec path was NOT \
                 encoded. Re-encode with the updated qwen3_tts branch (encode-knot.py).",
            );
        }
        let talker = Qwen3TtsTalker::new(Qwen3TtsTalkerConfig::default(), Arc::clone(&backend));
        eprintln!("  talker: {} text ids → generating codec frames...", text_ids.len());
        let t_gen = Instant::now();
        let (codes, n_frames) = talker
            .generate_codes(text_ids)
            .unwrap_or_else(|e| die(format!("talker generate: {e}")));
        eprintln!(
            "  talker: {:.2}s  {n_frames} frames x {} groups",
            t_gen.elapsed().as_secs_f32(),
            Qwen3TtsTalkerConfig::default().num_groups
        );
        (n_frames, Qwen3TtsTalkerConfig::default().num_groups, codes)
    } else {
        let path = args.codes.as_ref().unwrap();
        let (n_frames, nq, codes) = read_codes(path);
        eprintln!("  codes: {n_frames} frames x {nq} groups ({} tokens)", codes.len());
        (n_frames, nq, codes)
    };

    if nq != cfg.num_quantizers {
        die(format!(
            "nq {nq} != config num_quantizers {} — wrong codec",
            cfg.num_quantizers
        ));
    }

    // 3. Decode codec tokens → waveform.
    let decoder = Qwen3TtsCodecDecoder::new(cfg.clone(), backend);
    let t_dec = Instant::now();
    let wav = decoder
        .decode(&codes, n_frames)
        .unwrap_or_else(|e| die(format!("codec decode: {e}")));
    let sr = decoder.sample_rate();
    eprintln!(
        "  codec decode: {:.2}s  {} samples ({:.3}s @ {sr} Hz)",
        t_dec.elapsed().as_secs_f32(),
        wav.len(),
        wav.len() as f32 / sr as f32
    );

    // Peak-normalize to 0.95 full-scale before writing. The raw SEANet output is
    // un-normalized (observed peak >> 1.0), so a direct PCM16 write hard-clips —
    // which whisper hears as broadband noise rather than speech. Normalizing is a
    // lossless gain change that preserves the waveform shape.
    let raw_peak = wav.iter().fold(0.0f32, |a, &b| a.max(b.abs()));
    let wav_norm: Vec<f32> = if raw_peak > 1e-6 {
        let g = 0.95 / raw_peak;
        wav.iter().map(|&s| s * g).collect()
    } else {
        wav.clone()
    };
    eprintln!("  output peak {raw_peak:.3} → normalized to 0.95");

    // best-effort WAV dump (normalized).
    match write_wav(&args.out_wav, &wav_norm, sr) {
        Ok(()) => eprintln!("  wrote {}", args.out_wav),
        Err(e) => eprintln!("  WARNING: wav write failed: {e}"),
    }

    // Optional: dump the raw codec-code matrix so it can be re-decoded / re-sampled
    // without re-running the (slow) talker. Format matches read_codes().
    if let Ok(p) = std::env::var("TTS_DUMP_CODES") {
        use std::io::Write;
        if let Ok(mut f) = std::fs::File::create(&p) {
            let _ = f.write_all(&(n_frames as u32).to_le_bytes());
            let _ = f.write_all(&(nq as u32).to_le_bytes());
            for &c in &codes {
                let _ = f.write_all(&c.to_le_bytes());
            }
            eprintln!("  dumped codes → {p}");
        }
    }

    // 4. STRUCTURAL GATE.
    let n = wav.len();
    let nan = wav.iter().filter(|x| !x.is_finite()).count();
    let finite = nan == 0;

    let expected_len = n_frames * 1920; // 12.5 Hz × 1920 = 24 kHz
                                        // causal-conv edge effects can trim a few hundred samples; allow 1% slack.
    let len_slack = (expected_len / 100).max(2048);
    let len_ok = n > 0 && (n as isize - expected_len as isize).unsigned_abs() <= len_slack;

    let mean = if n > 0 {
        wav.iter().sum::<f32>() / n as f32
    } else {
        0.0
    };
    let var = if n > 0 {
        wav.iter().map(|x| (x - mean) * (x - mean)).sum::<f32>() / n as f32
    } else {
        0.0
    };
    let std = var.sqrt();
    let std_ok = std > MIN_STD;

    let peak = wav.iter().fold(0.0f32, |a, &b| a.max(b.abs()));
    // Structural gate (looser, per Taylor): require a finite, non-zero signal.
    // Absolute amplitude vs MAX_PEAK is a tuning detail — synthetic random codes
    // drive the un-clamped SEANet output above 1.0; real talker codes + an
    // output-normalization pass land it in [-1,1]. So the upper rail is observed,
    // not enforced.
    let peak_ok = peak.is_finite() && peak > 0.0;

    // dynamic range: peak vs the 10th-percentile abs amplitude (noise floor).
    let mut abs: Vec<f32> = wav.iter().map(|x| x.abs()).collect();
    abs.sort_by(|a, b| a.partial_cmp(b).unwrap_or(std::cmp::Ordering::Equal));
    let floor = if abs.is_empty() {
        0.0
    } else {
        abs[abs.len() / 10].max(1e-7)
    };
    let dr_db = 20.0 * (peak.max(1e-7) / floor).log10();
    let dr_ok = dr_db > MIN_DR_DB;

    println!("\n── tts-probe structural gate ──");
    println!("  finite (no NaN/Inf):      {finite}  (nan={nan})");
    println!("  length ~ n_frames*1920:   {len_ok}  ({n} vs {expected_len}, slack {len_slack})");
    println!("  std > {MIN_STD:e}:           {std_ok}  (std={std:.5})");
    println!("  peak finite + >0:         {peak_ok}  (peak={peak:.4}; norm cap {MAX_PEAK} observed, not enforced)");
    println!("  dynamic range > {MIN_DR_DB} dB:   {dr_ok}  (dr={dr_db:.1} dB)");
    eprintln!("  total wall: {:.2}s", t_all.elapsed().as_secs_f32());

    let pass = finite && len_ok && std_ok && peak_ok && dr_ok;
    if pass {
        println!("\nPASS: codec decoder produced valid, non-degenerate audio");
        std::process::exit(0);
    } else {
        println!("\nFAIL: degenerate audio (one or more structural checks failed)");
        std::process::exit(1);
    }
}
